from test_case
where project_id = #{projectId}
  and test_plan_id = #{testPlanId}
  and is_deleted = 0

select tc.id, tc.test_plan_id, tp.title as test_plan_title, tc.requirement_id, r.title as requirement_title, tc.task_id, t.name as task_name, tc.case_code, tc.title, tc.precondition, tc.steps, tc.expected_result, tc.actual_result, tc.execution_status, tc.tester_id, u.real_name as tester_name, tc.executed_at, tc.created_at, tc.updated_at from test_case tc left join test_plan tp on tp.id = tc.test_plan_id and tp.is_deleted = 0 left join requirement_info r on r.id = tc.requirement_id and r.is_deleted = 0 left join project_task t on t.id = tc.task_id and t.is_deleted = 0 left join sys_user u on u.id = tc.tester_id where tc.project_id = #{projectId} and tc.is_deleted = 0
and tc.test_plan_id = #{query.testPlanId}
and tc.execution_status = #{query.executionStatus}
and tc.tester_id = #{query.testerId}
order by tc.updated_at desc, tc.created_at desc

