select d.id, d.test_case_id, tc.title as test_case_title, d.requirement_id, r.title as requirement_title, d.task_id, t.name as task_name, d.defect_code, d.title, d.severity, d.priority, d.status, d.reporter_id, reporter.real_name as reporter_name, d.assignee_id, assignee.real_name as assignee_name, d.description, d.resolution, d.created_at, d.updated_at from defect_record d left join test_case tc on tc.id = d.test_case_id and tc.is_deleted = 0 left join requirement_info r on r.id = d.requirement_id and r.is_deleted = 0 left join project_task t on t.id = d.task_id and t.is_deleted = 0 left join sys_user reporter on reporter.id = d.reporter_id left join sys_user assignee on assignee.id = d.assignee_id where d.project_id = #{projectId} and d.is_deleted = 0
and d.status = #{query.status}
and d.severity = #{query.severity}
and d.assignee_id = #{query.assigneeId}
order by d.updated_at desc, d.created_at desc

